import os
from google.cloud import storage
from subprocess import call

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Extract conversion options from event metadata
    options = event.get('options', '')

    # Construct the full path to the image in Cloud Storage
    object_key = f"{file_name}"
    cloud_storage_client = storage.Client()
    bucket = cloud_storage_client.bucket(bucket_name)
    blob = bucket.blob(object_key)

    # Download the image from Cloud Storage
    blob.download_to_filename(f"/tmp/{file_name}")

    # Construct the convert command with options and output filename
    output_filename = f"{os.path.splitext(file_name)[0]}_converted{os.path.splitext(file_name)[1]}"
    cmd = ["convert", "-resize", "800x600", f"/tmp/{file_name}", f"/tmp/{output_filename}"]

    # Run the convert command using subprocess.call()
    call(cmd)

    # Upload the converted image back to Cloud Storage
    blob.upload_from_filename(f"/tmp/{output_filename}")

    # Clean up temporary files
    os.remove(f"/tmp/{file_name}")
    os.remove(f"/tmp/{output_filename}")